content.text:
#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check if either sensor is stale for more than 1000ms */
    if (controller->has_valid_temperature && (now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    if (controller->has_valid_level && (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    /* If we don't have valid readings yet, that's also a timeout condition */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return true;
    }
    return false;
}

static void controller_handle_timeout(controller_t *controller)
{
    controller->has_valid_temperature = false;
    controller->has_valid_level = false;
    controller_set_safe_idle(controller);
}

static bool controller_both_sensors_valid(const controller_t *controller)
{
    return controller->has_valid_temperature && controller->has_valid_level;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle input updates */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller_handle_timeout(controller);
        return output;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_temperature = false;
        controller_set_safe_idle(controller);
        return output;
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        return output;
    case CONTROLLER_INPUT_NONE:
    default:
        /* Check for timeout on idle steps */
        if (controller_check_sensor_timeout(controller, input.now_ms)) {
            controller_handle_timeout(controller);
            output.timed_out = true;
            return output;
        }
        break;
    }

    /* After processing input, check if we need to go to safe state due to timeout */
    if (controller_check_sensor_timeout(controller, input.now_ms)) {
        controller_handle_timeout(controller);
        output.timed_out = true;
        return output;
    }

    /* If both sensors are not valid yet, stay in safe idle */
    if (!controller_both_sensors_valid(controller)) {
        controller_set_safe_idle(controller);
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.changed =
            (previous_inlet_open != controller->inlet_open) ||
            (previous_heater_on != controller->heater_on) ||
            (previous_state != controller->state);
        return output;
    }

    /* Apply control policy */
    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    bool inlet_open = false;
    bool heater_on = false;
    controller_state_t state = CONTROLLER_STATE_SAFE_IDLE;

    /* Policy: If LEVEL < 60, command INLET OPEN and HEATER OFF */
    if (level < 60) {
        inlet_open = true;
        heater_on = false;
        state = CONTROLLER_STATE_FILLING;
    }
    /* Policy: If LEVEL > 75, command INLET CLOSED */
    else if (level > 75) {
        inlet_open = false;
        /* Heater decision based on temperature */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            heater_on = true;
            state = CONTROLLER_STATE_HEATING;
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < 45) {
            heater_on = true;
            state = CONTROLLER_STATE_HEATING;
        } else if (temp >= 45 && temp < 47) {
            /* Hold previous safe heater state */
            heater_on = controller->heater_on;
            state = CONTROLLER_STATE_HOLDING;
        } else if (temp >= 47 && temp <= 48) {
            /* Check if temperature is rising */
            if (controller->previous_temperature_c != 0 && temp > controller->previous_temperature_c) {
                heater_on = false;
                state = CONTROLLER_STATE_HOLDING;
            } else {
                heater_on = controller->heater_on;
                state = CONTROLLER_STATE_HOLDING;
            }
        } else if (temp > 48) {
            heater_on = false;
            state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            /* temp >= 45 and < 47 case - hold previous */
            heater_on = controller->heater_on;
            state = CONTROLLER_STATE_HOLDING;
        }
    }
    /* Policy: If 60 <= LEVEL <= 75 */
    else if (level >= 60 && level <= 75) {
        inlet_open = false;

        /* Policy: If TEMP < 45, command HEATER ON */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            heater_on = true;
            state = CONTROLLER_STATE_HEATING;
        }
        /* Policy: If 45 <= TEMP < 47, hold previous safe heater state */
        else if (temp >= 45 && temp < 47) {
            heater_on = controller->heater_on;
            state = CONTROLLER_STATE_HOLDING;
        }
        /* Policy: If 47 <= TEMP <= 48 and temperature is rising, command HEATER OFF */
        else if (temp >= 47 && temp <= 48) {
            if (controller->previous_temperature_c != 0 && temp > controller->previous_temperature_c) {
                heater_on = false;
                state = CONTROLLER_STATE_HOLDING;
            } else {
                heater_on = controller->heater_on;
                state = CONTROLLER_STATE_HOLDING;
            }
        }
        /* Policy: If TEMP > 48, command HEATER OFF */
        else if (temp > 48) {
            heater_on = false;
            state = CONTROLLER_STATE_SAFE_IDLE;
        }
    }

    /* Safety: If LEVEL < 55 at any time, keep HEATER OFF */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        heater_on = false;
        inlet_open = true;
        state = CONTROLLER_STATE_FILLING;
    }

    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;
    controller->state = state;

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

